import React, { useState, useEffect } from 'react';
import MainLayout from './components/Layout/MainLayout';
import KnowledgeBaseList from './components/KnowledgeBase/KnowledgeBaseList';
import CreateModal from './components/Modal/CreateModal';
import Button from './components/UI/Button';
import { Plus } from 'lucide-react';

function App() {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [knowledgeBases, setKnowledgeBases] = useState([]);
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage] = useState(10);

  // Load data from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('knowledgeBases');
    if (saved) {
      setKnowledgeBases(JSON.parse(saved));
    } else {
      // Add sample data for testing
      const sampleData = [
        {
          id: 1,
          name: 'Test',
          description: 'Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy.',
          createdOn: '14/07/2025'
        },
        {
          id: 2,
          name: 'Test',
          description: 'Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy.',
          createdOn: '14/07/2025'
        },
        {
          id: 3,
          name: 'Test',
          description: 'Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy.',
          createdOn: '14/07/2025'
        },
        {
          id: 4,
          name: 'Test',
          description: 'Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy.',
          createdOn: '14/07/2025'
        }
      ];
      setKnowledgeBases(sampleData);
      localStorage.setItem('knowledgeBases', JSON.stringify(sampleData));
    }
  }, []);

  const handleCreateKnowledgeBase = (newKnowledgeBase) => {
    const updated = [newKnowledgeBase, ...knowledgeBases];
    setKnowledgeBases(updated);
    localStorage.setItem('knowledgeBases', JSON.stringify(updated));
    setCurrentPage(1);
  };

  const handleCardClick = (knowledgeBase) => {
    console.log('Clicked:', knowledgeBase);
  };

  return (
    <MainLayout>
      <div className="mb-8 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold text-secondary">Knowledge Bases</h1>
          <p className="text-gray-500 mt-1">Manage and organize your knowledge repositories</p>
        </div>
        <Button onClick={() => setIsModalOpen(true)} variant="primary" size="lg">
          <Plus size={18} />
          Create New
        </Button>
      </div>

      <KnowledgeBaseList 
        knowledgeBases={knowledgeBases}
        onCardClick={handleCardClick}
        currentPage={currentPage}
        itemsPerPage={itemsPerPage}
        onPageChange={setCurrentPage}
      />

      <CreateModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onCreate={handleCreateKnowledgeBase}
      />
    </MainLayout>
  );
}

export default App;
